import 'dart:convert';

import '../lib/text_chunker.dart';
import '../lib/text_collector.dart';

void expectEqual(Object? actual, Object? expected) {
  if (actual != expected) {
    throw StateError('Expected $expected, got $actual');
  }
}

void main() {
  final externallySplit = <List<int>>[
    <int>[0x41, 0xE2],
    <int>[0x82],
    <int>[0xAC, 0x42],
  ];
  expectEqual(collectText(externallySplit), 'A\u{20AC}B');

  const original = 'left \u{1F642} right';
  final locallyChunked = chunkText(original, 6);
  for (final chunk in locallyChunked) {
    utf8.decode(chunk);
  }
  expectEqual(collectText(locallyChunked), original);
}
